pragma solidity ^0.8.20;

contract TokenVoting {
    address private owner;
    struct Candidate {
        string name;
        uint256 votes;
    }
    Candidate[] private candidates;
    mapping(address => bool) private voters;
    mapping(address => bool) private voted;

    event CandidateAdded(uint256 id, string name);
    event VotingRightsGranted(address voter);
    event VoteCast(address voter, uint256 candidateId);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function candidateCount() public view returns (uint256) {
        return candidates.length;
    }

    function candidateNames(uint256 id) public view returns (string memory) {
        require(id < candidates.length, "Invalid candidate ID");
        return candidates[id].name;
    }

    function candidateVotes(uint256 id) public view returns (uint256) {
        require(id < candidates.length, "Invalid candidate ID");
        return candidates[id].votes;
    }

    function addCandidate(string memory name) public onlyOwner {
        candidates.push(Candidate(name, 0));
        emit CandidateAdded(candidates.length - 1, name);
    }

    function grantVotingRights(address voter) public onlyOwner {
        require(!voters[voter], "Voting rights already granted");
        voters[voter] = true;
        emit VotingRightsGranted(voter);
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return voters[voter];
    }

    function vote(uint256 candidateId) public {
        require(hasVotingRights(msg.sender), "No voting rights");
        require(!voted[msg.sender], "Already voted");
        require(candidateId < candidates.length, "Invalid candidate ID");

        candidates[candidateId].votes += 1;
        voted[msg.sender] = true;
        emit VoteCast(msg.sender, candidateId);
    }
}
